import ipaddress
from urllib.parse import urlsplit
from urllib import parse as urlparse


_ALLOWED_SCHEMES = {"http", "https"}
# Domains allowed for redirects/checks. Populate with your permitted domains.
PERMITTED_DOMAINS: list[str] = ['trusted-site.com', 'partner-domain.org']


def _is_ascii(s: str) -> bool:
    try:
        s.encode("ascii")
        return True
    except UnicodeEncodeError:
        return False


