def is_domain_permitted(url: str) -> bool:
    """
    Check whether the URL's domain is within the configured PERMITTED_DOMAINS.

    Behavior:
      - Raises ValueError if the URL is invalid (delegates to validate_url).
      - Returns True if the URL's host exactly matches a permitted domain or is a subdomain of it.
      - For IP literals, only exact matches against entries in PERMITTED_DOMAINS are allowed.
      - Supports Unicode (IDN) domains in both the URL and PERMITTED_DOMAINS.

    Args:
        url: The URL to check.

    Returns:
        True if the URL's domain is permitted, False otherwise.
    """
    # Validate the URL first (raises ValueError on invalid).
    validate_url(url)

    parts = urlsplit(url)
    host, _ = _parse_hostport(parts.netloc)

    # If host is an IP literal, compare canonicalized IP strings against permitted entries.
    host_ip = _canonical_ip(host)
    if host_ip is not None:
        for entry in PERMITTED_DOMAINS:
            norm = _normalize_domain(entry)
            if not norm:
                # If normalization fails, try IP canonicalization directly
                try:
                    if str(ipaddress.ip_address(entry)) == host_ip:
                        return True
                except ValueError:
                    continue
            else:
                try:
                    if str(ipaddress.ip_address(norm)) == host_ip:
                        return True
                except ValueError:
                    continue
        return False

    # Otherwise, treat as a hostname and compare using normalized (punycode) domains.
    normalized_host = _normalize_domain(host)
    if not normalized_host:
        # Should not happen because validate_url already accepted it, but be defensive.
        return False

    for entry in PERMITTED_DOMAINS:
        permitted = _normalize_domain(entry)
        if not permitted:
            continue
        if normalized_host == permitted or normalized_host.endswith("." + permitted):
            return True

    return False


def construct_redirect_url(main_url: str, target_param: str) -> str:
    """
    Construct a secure redirect URL given a base application URL and a target parameter.

    Behavior:
      - If target_param is an absolute URL, it will be used as-is (after validation).
      - If target_param is a relative path/URL, it is resolved against main_url via urljoin.
      - The resulting URL must either be on the same host (or a subdomain) of main_url,
        or be within PERMITTED_DOMAINS (checked by is_domain_permitted).
      - Raises ValueError if validation fails or the target domain is not permitted.

    Args:
        main_url: The base URL of the application (e.g., "https://app.example.com/account").
        target_param: The desired redirect target; may be absolute or relative.

    Returns:
        The absolute redirect URL as a string.
    """
    # Validate and normalize main_url first
    validate_url(main_url)
    main_parts = urlparse.urlsplit(main_url)
    main_host, _ = _parse_hostport(main_parts.netloc)

    # If no target specified, return the main_url as a safe default
    if not isinstance(target_param, str) or not target_param.strip():
        return main_url

    # Resolve the target URL against main_url
    candidate_url = urlparse.urljoin(main_url, target_param)
    validate_url(candidate_url)

    cand_parts = urlparse.urlsplit(candidate_url)
    cand_host, _ = _parse_hostport(cand_parts.netloc)

    # Check if candidate is within the application's domain
    allowed_by_app_domain = False

    main_ip = _canonical_ip(main_host)
    cand_ip = _canonical_ip(cand_host)
    if main_ip is not None or cand_ip is not None:
        # IP-based hosts: only allow exact match
        allowed_by_app_domain = (main_ip is not None and cand_ip is not None and main_ip == cand_ip)
    else:
        norm_main = _normalize_domain(main_host)
        norm_cand = _normalize_domain(cand_host)
        if norm_main and norm_cand:
            if norm_cand == norm_main or norm_cand.endswith("." + norm_main):
                allowed_by_app_domain = True

    # Also allow if domain is in PERMITTED_DOMAINS
    allowed_by_permitted = is_domain_permitted(candidate_url)

    if not (allowed_by_app_domain or allowed_by_permitted):
        raise ValueError("Redirect target domain is not permitted.")

    return candidate_url

